import React from "react";
import "./PathologyPage.css";

const PathologyPage = () => {
  const checkups = [
    { title: "STD Checkups", img: "https://cdn-icons-png.flaticon.com/512/4202/4202843.png" },
    { title: "Fever Checkups", img: "https://cdn-icons-png.flaticon.com/512/2927/2927347.png" },
    { title: "PCOD Checkups", img: "https://cdn-icons-png.flaticon.com/512/2966/2966486.png" },
    { title: "Senior Citizen", img: "https://cdn-icons-png.flaticon.com/512/3048/3048122.png" },
  ];

  const tests = [
    { title: "Kidney Function Test", img: "https://cdn-icons-png.flaticon.com/512/616/616430.png" },
    { title: "Vitamin D, 25-Hydroxy", img: "https://cdn-icons-png.flaticon.com/512/2645/2645874.png" },
    { title: "HbA1c", img: "https://cdn-icons-png.flaticon.com/512/4225/4225918.png" },
    { title: "Lipid Profile", img: "https://cdn-icons-png.flaticon.com/512/4225/4225978.png" },
  ];

  const bodyCheckups = [
    { title: "Full Body Checkup - Essential", price: "₹1599", discount: "70% Off" },
    { title: "Full Body Checkup - Advanced", price: "₹2699", discount: "68% Off" },
    { title: "Ultra Full Body Checkup - Male", price: "₹11999", discount: "66% Off" },
  ];

  return (
    <div className="pathology-container">
      <h2 className="pathology-title">Popular Health Checkups</h2>
      <div className="scroll-container">
        {checkups.map((item, index) => (
          <div key={index} className="card">
            <img src={item.img} alt={item.title} />
            <h3>{item.title}</h3>
          </div>
        ))}
      </div>

      <h2 className="pathology-title">Popular Health Tests</h2>
      <div className="scroll-container">
        {tests.map((item, index) => (
          <div key={index} className="card">
            <img src={item.img} alt={item.title} />
            <h3>{item.title}</h3>
          </div>
        ))}
      </div>

      <h2 className="pathology-title">Full Body Checkups</h2>
      <div className="scroll-container">
        {bodyCheckups.map((item, index) => (
          <div key={index} className="checkup-card">
            <div className="price-section">
              <h3>{item.title}</h3>
              <p className="price">{item.price}</p>
              <span className="discount">{item.discount}</span>
            </div>
            <button className="btn">View Details</button>
            <button className="btn add-cart">Add to Cart</button>
          </div>
        ))}
      </div>
    </div>
  );
};

export default PathologyPage;
